// High-frequency energy measurement for the Task 4.2 camera-crispness gate.
//
// "Crisp" is converted into a measurable quantity: the variance of the Laplacian
// of the luminance image inside a region. A sharp, re-rasterized text region has
// strong high-frequency edges → high Laplacian variance. A blurry upscaled bitmap
// of the same region has its high frequencies smeared away → low variance. This is
// the standard image-processing focus/sharpness metric.
//
// Pure: decode a PNG region → luminance → 3x3 Laplacian convolution → variance.

import { PNG } from "pngjs";

export type Region = { x: number; y: number; width: number; height: number };

/** Decode a PNG buffer to RGBA pixels + dims. */
function decode(buffer: Buffer): { data: Buffer; width: number; height: number } {
  const png = PNG.sync.read(buffer);
  return { data: png.data, width: png.width, height: png.height };
}

/** Rec. 601 luma for a pixel offset in an RGBA buffer. */
function lumaAt(data: Buffer, idx: number): number {
  return 0.299 * data[idx]! + 0.587 * data[idx + 1]! + 0.114 * data[idx + 2]!;
}

/**
 * Variance of the 3x3 Laplacian over a region of a PNG. Higher = sharper (more
 * high-frequency edge energy). The region is clamped to the image bounds.
 */
export function laplacianVariance(pngBuffer: Buffer, region: Region): number {
  const { data, width, height } = decode(pngBuffer);

  const x0 = Math.max(1, Math.floor(region.x));
  const y0 = Math.max(1, Math.floor(region.y));
  const x1 = Math.min(width - 1, Math.floor(region.x + region.width));
  const y1 = Math.min(height - 1, Math.floor(region.y + region.height));
  if (x1 <= x0 || y1 <= y0) return 0;

  const lap: number[] = [];
  for (let y = y0; y < y1; y++) {
    for (let x = x0; x < x1; x++) {
      const c = (y * width + x) * 4;
      const up = ((y - 1) * width + x) * 4;
      const down = ((y + 1) * width + x) * 4;
      const left = (y * width + (x - 1)) * 4;
      const right = (y * width + (x + 1)) * 4;
      // 4-neighbour Laplacian kernel.
      const value =
        4 * lumaAt(data, c) -
        lumaAt(data, up) -
        lumaAt(data, down) -
        lumaAt(data, left) -
        lumaAt(data, right);
      lap.push(value);
    }
  }
  if (lap.length === 0) return 0;

  let mean = 0;
  for (const v of lap) mean += v;
  mean /= lap.length;
  let variance = 0;
  for (const v of lap) variance += (v - mean) * (v - mean);
  variance /= lap.length;
  return variance;
}

/** Crop a region out of a PNG and re-encode it (for 1:1 visual-proof crops). */
export function cropPng(pngBuffer: Buffer, region: Region): Buffer {
  const png = PNG.sync.read(pngBuffer);
  const x0 = Math.max(0, Math.floor(region.x));
  const y0 = Math.max(0, Math.floor(region.y));
  const w = Math.min(png.width - x0, Math.floor(region.width));
  const h = Math.min(png.height - y0, Math.floor(region.height));
  const out = new PNG({ width: w, height: h });
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const src = ((y + y0) * png.width + (x + x0)) * 4;
      const dst = (y * w + x) * 4;
      out.data[dst] = png.data[src]!;
      out.data[dst + 1] = png.data[src + 1]!;
      out.data[dst + 2] = png.data[src + 2]!;
      out.data[dst + 3] = png.data[src + 3]!;
    }
  }
  return PNG.sync.write(out);
}
