// Calibrated indistinguishability thresholds for the Tier-3 evaluator.
//
// Source: /Users/jake/plain/fidelity-lab/calibration/calibrated-thresholds.json
// Calibration: SINGLE-RATER (jake), provisional-certified. 70 blind/randomized
// human-labelled pairs; honesty checks 3/3; Fleiss' kappa n/a (n=1). A 3-rater
// pass would harden this. Treat the bar as good-enough-to-build-on, NOT final.
//
// FINDINGS.md override: the JSON's `recommendedPrimary` is SSIM, but for UI the
// pixel-diff metric is better-aligned (SSIM over-rejects flat-background UI).
// So: pixel-diff is PRIMARY, and the gate is the UNION of the two metrics.

export const CALIBRATION_PROVENANCE =
  "single-rater (jake), provisional — 70 pairs, honesty 3/3, kappa n/a (n=1)";

/** pixelDiff% must be <= this to count as indistinguishable. */
export const PIXEL_DIFF_MAX = 1.82335;

/** SSIM must be >= this to count as indistinguishable. */
export const SSIM_MIN = 0.9905;

export type Metrics = {
  pixelDiffPct: number;
  ssim: number;
};

export type Verdict = {
  pass: boolean;
  /** Which metric carried the pass (pixel-diff is primary for UI). */
  reason: "pixelDiff" | "ssim" | "both" | "neither";
  primaryMetric: "pixelDiff";
  pixelDiffPct: number;
  ssim: number;
  thresholds: { pixelDiffMax: number; ssimMin: number };
  provenance: string;
};

/**
 * Union verdict: indistinguishable iff pixelDiff <= 1.82% OR SSIM >= 0.9905.
 * Pixel-diff is the primary metric for UI per FINDINGS.md.
 */
export function verdict(metrics: Metrics): Verdict {
  const pixelOk = metrics.pixelDiffPct <= PIXEL_DIFF_MAX;
  const ssimOk = metrics.ssim >= SSIM_MIN;
  const reason: Verdict["reason"] = pixelOk && ssimOk
    ? "both"
    : pixelOk
      ? "pixelDiff"
      : ssimOk
        ? "ssim"
        : "neither";
  return {
    pass: pixelOk || ssimOk,
    reason,
    primaryMetric: "pixelDiff",
    pixelDiffPct: metrics.pixelDiffPct,
    ssim: metrics.ssim,
    thresholds: { pixelDiffMax: PIXEL_DIFF_MAX, ssimMin: SSIM_MIN },
    provenance: CALIBRATION_PROVENANCE,
  };
}
