// Determinism check for the Tier-3 evaluator.
//
// The auto-update loop (Phase 5) rests on one fact: re-rendering an UNCHANGED
// screen is bit-for-bit identical, so any non-identical re-render is real product
// drift. This module is the comparator that proves it. The lab measured 0.000%
// self-diff with seek-stepping (FINDINGS Stage D) — this gate enforces it.

import { createHash } from "node:crypto";

import { decodePng, diffImages } from "./diff.js";

export type DeterminismResult = {
  runs: number;
  frameCount: number;
  /** True iff every frame's bytes are identical across all runs. */
  byteIdentical: boolean;
  /** Worst per-frame pixelDiff% across all run-pairs (0 when byte-identical). */
  maxFramePixelDiff: number;
  /** sha256 of the concatenated frames for each run. */
  runHashes: string[];
};

/** A producer renders the same input and returns its frames as PNG buffers. */
export type FrameProducer = () => Promise<Buffer[]>;

function sha256(buffers: Buffer[]): string {
  const hash = createHash("sha256");
  for (const buffer of buffers) hash.update(buffer);
  return hash.digest("hex");
}

/**
 * Run `produce` `runs` times and compare. Frame bytes are compared directly;
 * when they differ, the calibrated pixel-diff quantifies by how much (so a
 * failure report can show the drift, not just "not identical").
 */
export async function checkDeterminism(
  produce: FrameProducer,
  runs = 2,
): Promise<DeterminismResult> {
  if (runs < 2) throw new Error("Determinism check needs at least 2 runs.");

  const allRuns: Buffer[][] = [];
  for (let i = 0; i < runs; i += 1) {
    allRuns.push(await produce());
  }

  const frameCount = allRuns[0]?.length ?? 0;
  for (const run of allRuns) {
    if (run.length !== frameCount) {
      throw new Error(
        `Non-determinism: runs produced different frame counts (${run.length} vs ${frameCount}).`,
      );
    }
  }

  const runHashes = allRuns.map(sha256);
  const byteIdentical = runHashes.every((h) => h === runHashes[0]);

  let maxFramePixelDiff = 0;
  if (!byteIdentical) {
    const base = allRuns[0]!;
    for (let r = 1; r < allRuns.length; r += 1) {
      const other = allRuns[r]!;
      for (let f = 0; f < frameCount; f += 1) {
        const a = base[f]!;
        const b = other[f]!;
        if (a.equals(b)) continue;
        const { pixelDiffPct } = diffImages(decodePng(a), decodePng(b));
        if (pixelDiffPct > maxFramePixelDiff) maxFramePixelDiff = pixelDiffPct;
      }
    }
  }

  return { runs, frameCount, byteIdentical, maxFramePixelDiff, runHashes };
}

/** Throws unless the producer is bit-for-bit deterministic across runs. */
export async function assertDeterministic(
  produce: FrameProducer,
  runs = 2,
): Promise<DeterminismResult> {
  const result = await checkDeterminism(produce, runs);
  if (!result.byteIdentical) {
    throw new Error(
      `Render is non-deterministic: maxFramePixelDiff=${result.maxFramePixelDiff}% ` +
        `over ${result.frameCount} frames (hashes: ${result.runHashes.join(", ")}).`,
    );
  }
  return result;
}
